PTX_KERNELS = {
    "sum_hw": PTXKernelSpec(
        entry="sum_hw_kernel",
        grid=lambda x, sums, batch, channels, height, width: (int(batch * channels), 1, 1),
        block=(256, 1, 1),
        arg_types=("tensor", "tensor", "int32", "int32", "int32", "int32"),
    ),
    "final_lse": PTXKernelSpec(
        entry="final_lse_kernel",
        grid=lambda sums, weight, conv_bias, extra_bias, out, batch, height, width, kernel_size: (int(batch), 1, 1),
        block=(128, 1, 1),
        arg_types=("tensor", "tensor", "tensor", "tensor", "tensor", "int32", "int32", "int32", "int32"),
    ),
}

class ModelNew(nn.Module):
    def __init__(self, in_channels, out_channels, kernel_size, bias_shape):
        super().__init__()
        torch.manual_seed(42)
        self.conv_transpose = nn.ConvTranspose2d(in_channels, out_channels, kernel_size)
        self.bias = nn.Parameter(torch.randn(bias_shape))
        self.runner = PTXModuleRunner(PTX_SOURCES, PTX_KERNELS)
        self.kernel_size = int(kernel_size)

    def forward(self, x):
        sums = torch.empty((x.size(0), x.size(1)), device=x.device, dtype=x.dtype)
        out = torch.empty((x.size(0), 1), device=x.device, dtype=x.dtype)
        self.runner.launch("sum_hw", x, sums, x.size(0), x.size(1), x.size(2), x.size(3))
        self.runner.launch(
            "final_lse",
            sums,
            self.conv_transpose.weight,
            self.conv_transpose.bias,
            self.bias,
            out,
            x.size(0),
            x.size(2),
            x.size(3),
            self.kernel_size,
        )
        return out
